void HAL_GPIO_EXTI_Callback(uint16_t GPIO_Pin)
{
	  static uint32_t lastPress = 0;
	  uint32_t now = HAL_GetTick();

	  if (GPIO_Pin == BUTTON_USER_PIN)   // <-- đổi thành macro pin thật của board bạn
	  {
	    if ((now - lastPress) > 200)     // debounce phần mềm 200ms
	    {
	      buttonPressed = 1;
	      lastPress = now;
	    }
	  }
}


